import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import BrandLogo from './BrandLogo';

const UserNavLinks = [
  { to: '/dashboard', icon: 'ŌŚł', label: 'Dashboard' },
  { to: '/scores', icon: 'Ōø│', label: 'My Scores' },
  { to: '/draws', icon: '­¤Ä▓', label: 'Draws & Results' },
  { to: '/charity', icon: '­¤ÆÜ', label: 'My Charity' },
  { to: '/subscription', icon: 'Ō£”', label: 'Subscription' },
];

const AdminNavLinks = [
  { to: '/admin', icon: 'ŌŚł', label: 'Overview' },
  { to: '/admin/users', icon: '­¤æź', label: 'Users' },
  { to: '/admin/draws', icon: '­¤Ä▓', label: 'Draw System' },
  { to: '/admin/winners', icon: '­¤Åå', label: 'Winners' },
  { to: '/admin/charities', icon: '­¤ÆÜ', label: 'Charities' },
];

export default function AppLayout({ children }) {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [mobileOpen, setMobileOpen] = useState(false);

  const links = user?.role === 'admin' ? AdminNavLinks : UserNavLinks;

  const handleLogout = () => { logout(); navigate('/'); };

  const SidebarContent = () => (
    <div className="flex flex-col h-full">
      {/* Logo */}
      <div className="px-6 py-6 border-b border-charcoal-800/60">
        <div>
          <BrandLogo compact showTagline={false} />
          <div className="text-xs text-charcoal-500 font-body mt-3">
            {user?.role === 'admin' ? 'Admin Panel' : 'Player Portal'}
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav className="flex-1 px-3 py-4 space-y-1">
        {links.map(link => (
          <NavLink
            key={link.to}
            to={link.to}
            end={link.to === '/dashboard' || link.to === '/admin'}
            className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}
            onClick={() => setMobileOpen(false)}
          >
            <span className="text-base w-5 text-center">{link.icon}</span>
            <span>{link.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* User info + logout */}
      <div className="px-3 py-4 border-t border-charcoal-800/60">
        <div className="flex items-center gap-3 px-3 py-3 rounded-xl bg-charcoal-800/40 mb-2">
          <div className="w-8 h-8 rounded-full bg-forest-700 flex items-center justify-center text-sm font-bold text-white">
            {user?.name?.[0]?.toUpperCase()}
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-sm font-medium text-white truncate">{user?.name}</div>
            <div className="text-xs text-charcoal-500 truncate">{user?.email}</div>
          </div>
        </div>
        <button onClick={handleLogout} className="sidebar-link w-full text-red-400 hover:text-red-300 hover:bg-red-900/20">
          <span className="text-base w-5 text-center">ŌåÆ</span>
          <span>Sign Out</span>
        </button>
      </div>
    </div>
  );

  return (
    <div className="flex h-screen bg-charcoal-950 overflow-hidden">
      {/* Desktop Sidebar */}
      <aside className="hidden md:flex flex-col w-64 bg-charcoal-900/80 border-r border-charcoal-800/60 shrink-0">
        <SidebarContent />
      </aside>

      {/* Mobile Sidebar Overlay */}
      {mobileOpen && (
        <div className="fixed inset-0 z-50 md:hidden">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setMobileOpen(false)} />
          <aside className="absolute left-0 top-0 bottom-0 w-72 bg-charcoal-900 border-r border-charcoal-800/60 flex flex-col z-10">
            <SidebarContent />
          </aside>
        </div>
      )}

      {/* Main content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Mobile topbar */}
        <header className="md:hidden flex items-center justify-between px-4 py-3 border-b border-charcoal-800/60 bg-charcoal-900/80 shrink-0">
          <BrandLogo compact showTagline={false} />
          <button onClick={() => setMobileOpen(true)} className="p-2 rounded-lg text-charcoal-400 hover:text-white hover:bg-charcoal-800">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
        </header>

        {/* Page content */}
        <main className="flex-1 overflow-y-auto p-4 md:p-8 animate-fade-in">
          {children}
        </main>
      </div>
    </div>
  );
}
